patches.fixed_method:
static int toJavaVersionInt(String version) {
    if (version == null || version.isEmpty()) {
        return 0;
    }
    int result = toVersionInt(toJavaVersionIntArray(version, JAVA_VERSION_TRIM_SIZE));
    return (int) result;
}

